// Helper: get motors by series
export const getMotorsBySeries = (series: Motor['series']) => motors.filter(m => m.series === series);

// Helper: get motor by slug
export const getMotorBySlug = (slug: string) => motors.find(m => m.slug === slug);

// Helper: get HP as display string
export const getHPDisplay = (hp: Motor['hp']): string => {
  if (typeof hp === 'object' && hp !== null) return `${hp.low}–${hp.high} HP`;
  return `${hp} HP`;
};
